const { properties } = items[0].json;
const CHUNK = 100;
const batches = [];
for (let i = 0; i < properties.length; i += CHUNK) {
  batches.push({ json: { properties: properties.slice(i, i + CHUNK) } });
}
return batches;

const total = items.reduce((s, i) => s + (i.json.ingested || 0), 0);
console.log(`Done. Ingested: ${total}`);
return [{ json: { status: 'complete', total_ingested: total, timestamp: new Date().toISOString() } }];
